import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import * as FileSaver from 'file-saver';
import { useStyles } from '../styles'
import { Button, Input } from '@material-ui/core';

const Cei = () => {

  const [CeiContent, setCeiContent] = useState([])
  const [CeiHeaders, setCeiHeaders] = useState([])

  const [OutstandingSalesContent, setOutstandingSalesContent] = useState([])
  const [OutstandingSalesHeader, setOutstandingSalesHeader] = useState([])

  const classes = useStyles()

  const excelReader = (data, isFirstFile) => {
    let renderedData = XLSX.read(data, { type: 'binary' });
    const dataParse = XLSX.utils.sheet_to_json(renderedData.Sheets[renderedData.SheetNames[0]], { header: 1 });

    if (isFirstFile) {
        const headers = []
        for (let i = 0; i < dataParse[2].length; i++) {
            headers.push(dataParse[2][i])
        }
        const content = []
        for (let i = 3; i < dataParse.length; i++) {
            const cols = dataParse[i] // row information
            // 6 11 12 18
            if (dataParse[i][6] != '9999-99-99') {
                let d = excelDateToJSDate(dataParse[i][6])
                if (d == 'Invalid Date') {
                    dataParse[i][6] = ''
                } else {
                    dataParse[i][6] = (d.getMonth()+1) + "/" + d.getDate() + "/" + d.getFullYear()
                }
            }
            if (dataParse[i][11] != '9999-99-99') {
                let d = excelDateToJSDate(dataParse[i][11])
                if (d == 'Invalid Date') {
                    dataParse[i][11] = ''
                } else {
                    dataParse[i][11] = (d.getMonth()+1) + "/" + d.getDate() + "/" + d.getFullYear()
                }
            }
            if (dataParse[i][12] != '9999-99-99') {
                let d = excelDateToJSDate(dataParse[i][12])
                if (d == 'Invalid Date') {
                    dataParse[i][12] = ''
                } else {
                    dataParse[i][12] = (d.getMonth()+1) + "/" + d.getDate() + "/" + d.getFullYear()
                }
            }
            if (dataParse[i][18] != '9999-99-99') {
                let d = excelDateToJSDate(dataParse[i][18])
                if (d == 'Invalid Date') {
                    dataParse[i][18] = ''
                } else {
                    dataParse[i][18] = (d.getMonth()+1) + "/" + d.getDate() + "/" + d.getFullYear()
                }
            }
            dataParse[i][16] = '' // change 'Provide Input' == ''
            content.push(cols)
        }
        setCeiHeaders(headers)
        setCeiContent(content)
        return
    }

    const headers = []
    for (let i = 0; i < dataParse[0].length; i++) {
        headers.push(dataParse[0][i])
    }

    const content = []
    for (let i = 1; i < dataParse.length; i++) {
        const cols = dataParse[i] // row information
        content.push(cols)
    }

    setOutstandingSalesHeader(headers)
    setOutstandingSalesContent(content)
    
  }

  const onFileChange = (e, isFirstFile) => {
    e.preventDefault();
    var files = e.target.files, f = files[0];
    var reader = new FileReader();
    reader.onload = function (e) {
      excelReader(e.target.result, isFirstFile)
    };
    reader.readAsBinaryString(f)
  }

    const excelDateToJSDate = (serial) => {
        var utc_days = Math.floor(serial - 25569);
        var utc_value = utc_days * 86400;
        var date_info = new Date(utc_value * 1000);
        return new Date(date_info.getFullYear(), date_info.getMonth(), date_info.getDate());
    }


    const downloadFile = () => {
        for (let i = 0; i < CeiContent.length; i++) {
            let pn = CeiContent[i][2]
            let mpn = CeiContent[i][4]
            let po = CeiContent[i][7]
            let lineNum = CeiContent[i][8]
            let qty = CeiContent[i][9]

            for (let j = 0; j < OutstandingSalesContent.length; j++) {
                let line = OutstandingSalesContent[j][0]
                let cpo = OutstandingSalesContent[j][1]
                let cpn = OutstandingSalesContent[j][2]
                let stockCode = OutstandingSalesContent[j][4]
                let delQty = OutstandingSalesContent[j][7]

                if (cpo == po && cpn == pn && stockCode == mpn && qty == delQty && line == lineNum) {
                    let date = excelDateToJSDate(OutstandingSalesContent[j][8])
                    // console.log(cpo, cpn, orderQty, mfgPartId, date, (date.getMonth()+1) + "/" + date.getDate() + "/" + date.getFullYear())
                    CeiContent[i][16] = (date.getMonth()+1) + "/" + date.getDate() + "/" + date.getFullYear()
                    // CeiContent[i][14] = OutstandingSalesContent[j][7] // match to oorcontent[14]
                }
            }
    }

    let wbData = []

    /* Write and Download File */
    for (let i = 0; i < CeiContent.length; i++) {
        let rowData = {}
        for (let j = 0; j < CeiContent[i].length; j++) {
            rowData[CeiHeaders[j]] = CeiContent[i][j]
        }
        wbData.push(rowData)
    }

    const ws = XLSX.utils.json_to_sheet(wbData, { header: CeiHeaders })
    let wb = { Sheets: { 'data': ws }, SheetNames: ['data'] }
    const excelBuffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
    const dd = new Blob([excelBuffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8' });
    FileSaver.saveAs(dd, 'CEI_OOR_final.xlsx');
  }

  return (
    <div className={classes.root}>
        <span style={{ fontSize: '30px', marginBottom: '30px', textAlign: 'center', fontWeight: 'bold' }}>
            CEI OOR Report
        </span>
        <span style={{ fontSize: '18px', margin: '30px 0px 30px 0px', textAlign: 'left', fontWeight: "normal" }}>
            This program will input our delivery schedule into customer's Open Order Report (OOR) report.<br/>
            This applies to CEI only, as it is built based on CEI's OOR template<br/>
        </span>
        <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
            <div className={classes.fileUploadWrapper}>
                <span className={classes.label}>CEI File</span>
                <Input onChange={(event) => onFileChange(event, true)} type="file" className={classes.fileUpload} />
            </div>
            <div className={classes.fileUploadWrapper}>
                <span className={classes.label}>Outstanding Sales (Schedule)</span>
                <Input onChange={(event) => onFileChange(event, false)} type="file" className={classes.fileUpload} />
            </div>
        </div>
        <button onClick={() => downloadFile()} className={classes.download}>
            Download
        </button>
        <div style={{ justifyContent: 'center', alignItems: 'center', display: 'flex', flexDirection: 'column' }}>
            <h3>Your Uploaded File <span style={{ fontWeight: 'bold', color: 'red', fontSize: '20px' }}>MUST</span> follow the following format: </h3>
            <img alt="Sample Format" src={require('../assets/cei_template.jpg')} width={"80%"} style={{ borderRadius: "10px" }} />
        </div>
    </div>
  );
}

export default Cei;
