import React, { useState } from 'react';
import { useStyles } from '../styles'
import { Backdrop, CircularProgress, FormControl, Input, InputLabel, MenuItem, Select } from '@material-ui/core';
import axios from 'axios';
import { GET_PRESIGNED_URL } from '../utils';

const QuotationModuleDownload = () => {
    const classes = useStyles()
    const [loading, setLoading] = useState(false)
    const [priceList, setPirceList] = useState(null)
    const [supplier, setSupplier] = useState("")
    const [manufacturer, setManufacturer] = useState("")
    const [filename, setFilename] = useState("")

    const uploadPriceList = (event) => {
        console.log(event.target.files[0])
        setPirceList(event.target.files[0])
    }

    const handleSupplierChange = (event) => {
        setSupplier(event.target.value)
    }

    const handleManufacturerChange = (event) => {
        setManufacturer(event.target.value)
    }

    const postRequest = async () => {
        setLoading(true)
        if (priceList == null || supplier == "" || manufacturer == "") {
            alert('ensure all files have ben uploaded before proceeding')
            setLoading(false)
            return
        }

        let url = ""
        // get pre-signed url
        try {
            await axios.get(GET_PRESIGNED_URL, {
                params: {
                    supplier: supplier,
                    manufacturer: manufacturer,
                    type: priceList["type"],
                    action: 'quotation',
                }
            })
                .then(res => {
                    url = JSON.parse(res.data.body)["url"]
                    setFilename(JSON.parse(res.data.body)["file_name"])
                }).catch(err => {
                    console.log(err)
                    alert(err)
                    return
                });

            if (url == "") {
                console.log("url is empty")
                return
            }

            // upload to s3
            await axios.put(url, priceList, {
                headers: {
                    'Content-Type': priceList["type"],
                }
            }).then(res => {
                console.log("file uploaded successfully")
            }).catch(err => {
                alert(err)
            });
        } catch (error) {
            console.log(error)
        } finally {
            setLoading(false)
        }
    }

    const downloadQuotation = async () => {
        setLoading(true)
        try {
            if (filename == "") return

            let url = ""
            // retrieve pre signed url first
            console.log(filename)
            let updated_filename = filename.split("/")[1]
            updated_filename = "filled_quotation/" + updated_filename
            await axios.get(GET_PRESIGNED_URL, {
                params: {
                    action: 'download',
                    filename: updated_filename.replace("/", "___").replace(".xlsx", "")
                }
            })
                .then(res => {
                    url = JSON.parse(res.data.body)["url"]
                }).catch(err => {
                    console.log(err)
                    alert(err)
                    return
                });

            if (url == "") {
                console.log("url is empty")
                return
            }

            await axios.get(url, {
                responseType: 'arraybuffer'
            }).then(async res => {
                const url = window.URL.createObjectURL(new Blob([res.data]));
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', `quotation.xlsx`);
                document.body.appendChild(link);
                link.click();
            }).catch(err => {
                alert(err)
            });
        } catch (error) {
            console.log(error)
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className={classes.root}>
            <span style={{ fontSize: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                Quotation
            </span>
            {/* <span style={{ fontSize: '18px', margin: '30px 0px 30px 0px', textAlign: 'left', fontWeight: "normal" }}>
                 <br/>
            </span> */}
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <FormControl fullWidth>
                    <InputLabel id="demo-simple-select-label">Supplier</InputLabel>
                    <Select
                        labelId="demo-simple-select-label"
                        id="demo-simple-select"
                        value={supplier}
                        label="Supplier"
                        onChange={handleSupplierChange}
                    >
                        <MenuItem value={"pushton"}>Pushton</MenuItem>
                        <MenuItem value={"phoenix_singapore"}>Phoenix Singapore</MenuItem>
                        <MenuItem value={"mill_max"}>Mill-Max</MenuItem>
                        <MenuItem value={"cinch"}>Cinch</MenuItem>
                        <MenuItem value={"ept"}>EPT</MenuItem>
                        <MenuItem value={"abbatron"}>Abbatron</MenuItem>
                        <MenuItem value={"coto"}>COTO</MenuItem>
                        <MenuItem value={"iqd"}>IQD</MenuItem>
                        <MenuItem value={"pickering"}>Pickering</MenuItem>
                        <MenuItem value={"triad"}>Triad</MenuItem>
                        <MenuItem value={"trompeter"}>Trompeter</MenuItem>
                        <MenuItem value={"aim_cambridge"}>Aim Cambridge</MenuItem>
                        <MenuItem value={"qualtek"}>Qualtek</MenuItem>
                        {/* <MenuItem value={"johnson"}>Johnson</MenuItem>
                        <MenuItem value={"edac"}>EDAC</MenuItem> */}
                    </Select>
                </FormControl>
                <div style={{ width: "20px" }}></div>
                <FormControl fullWidth>
                    <InputLabel id="demo-simple-select-label">Manufacturer</InputLabel>
                    <Select
                        labelId="demo-simple-select-label"
                        id="demo-simple-select"
                        value={manufacturer}
                        label="Supplier"
                        onChange={handleManufacturerChange}
                    >
                        <MenuItem value={"phoenix_contact"}>Phoenix Contact</MenuItem>
                        <MenuItem value={"mill_max"}>Mill-Max</MenuItem>
                        <MenuItem value={"cinch"}>Cinch</MenuItem>
                        <MenuItem value={"ept"}>EPT</MenuItem>
                        <MenuItem value={"abbatron"}>Abbatron</MenuItem>
                        <MenuItem value={"coto"}>COTO</MenuItem>
                        <MenuItem value={"iqd"}>IQD</MenuItem>
                        <MenuItem value={"pickering"}>Pickering</MenuItem>
                        <MenuItem value={"triad"}>Triad</MenuItem>
                        <MenuItem value={"trompeter"}>Trompeter</MenuItem>
                        <MenuItem value={"aim_cambridge"}>Aim Cambridge</MenuItem>
                        <MenuItem value={"qualtek"}>Qualtek</MenuItem>
                    </Select>
                </FormControl>
            </div>
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Price list</span>
                    <Input onChange={(event) => uploadPriceList(event)} type="file" className={classes.fileUpload} />
                </div>
                {/* <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>New File</span>
                    <Input onChange={(event) => uploadNew(event)} type="file" className={classes.fileUpload} />
                </div> */}
            </div>
            <div style={{ marginTop: '50px' }}>
                <button onClick={() => postRequest()} className={classes.download}>
                    Upload Quotation
                </button>
                <button onClick={() => downloadQuotation()} className={classes.download}>
                    Download
                </button>
            </div>
            <Backdrop
                sx={{ color: '#fff', zIndex: (theme) => theme.zIndex.drawer + 1 }}
                open={loading}
                style={{ position: 'absolute', zIndex: 10 }}
            >
                <CircularProgress color="inherit" />
            </Backdrop>
        </div>
    );
}

export default QuotationModuleDownload;